export type Locale = "en" | "zh";

export type Bilingual = { en: string; zh: string };

export type Topic = {
  slug: string;
  title: Bilingual;
  summary: Bilingual;
};

export type Unit = {
  slug: string;
  number: number;
  title: Bilingual;
  description: Bilingual;
  topics: Topic[];
};

export type Subject = {
  slug: string;
  title: Bilingual;
  tagline: Bilingual;
  units: Unit[];
};

export type NoteBlock =
  | { kind: "heading"; text: Bilingual }
  | { kind: "paragraph"; text: Bilingual }
  | { kind: "callout"; label: Bilingual; text: Bilingual }
  | { kind: "list"; items: Bilingual[] }
  | { kind: "math"; tex: string; caption?: Bilingual }
  | { kind: "math-inline-line"; segments: Array<{ t: "text"; text: Bilingual } | { t: "tex"; tex: string }> }
  | { kind: "molecule"; smiles: string; label?: Bilingual; width?: number; height?: number }
  | { kind: "molecule-row"; items: Array<{ smiles: string; label?: Bilingual }>; width?: number; height?: number }
  | { kind: "mol3d"; geometry: "linear" | "trigonal-planar" | "tetrahedral" | "trigonal-pyramidal" | "bent" | "trigonal-bipyramidal" | "octahedral" | "see-saw" | "square-planar" }
  | { kind: "lewis"; name: string; label?: Bilingual }
  | { kind: "lewis-row"; names: string[] }
  | {
      kind: "chem-chart";
      chartType:
        | "heating-curve"
        | "maxwell-boltzmann"
        | "bond-potential"
        | "beer-lambert"
        | "pes-neon"
        | "successive-ie-mg"
        | "solubility-vs-t"
        | "real-gas-deviation"
        | "titration-strong"
        | "concentration-vs-time"
        | "reaction-profile"
        | "catalyst-effect"
        | "multistep-profile"
        | "thermal-equilibrium"
        | "hess-cycle"
        | "equilibrium-approach"
        | "lechatelier-shift"
        | "titration-weak"
        | "galvanic-cell"
        | "nernst-curve";
    }
  | { kind: "mass-spectrum"; peaks: Array<{ mz: number; pct: number }>; title?: Bilingual }
  | {
      kind: "chart";
      chartType:
        | "supply-demand"
        | "ppc"
        | "perfect-comp-firm"
        | "monopoly"
        | "monop-comp-sr"
        | "monop-comp-lr"
        | "monopsony"
        | "labor-market"
        | "labor-market-shift"
        | "labor-market-tax"
        | "negative-externality"
        | "positive-externality"
        | "lorenz-curve";
    }
  | {
      kind: "table";
      caption: Bilingual;
      columns: Bilingual[];
      rows: Bilingual[][];
      highlightLastRow?: boolean;
    }
  | { kind: "orbital"; orbital: "1s" | "2s" | "2p" | "3s" | "3p" | "3dz2" | "3dxy" | "3dxz" | "3dyz" | "3dx2y2" }
  | { kind: "born-haber"; compound: "NaCl" | "MgO" | "CaF2" }
  | { kind: "arrhenius-plot" }
  | { kind: "titration-sim" }
  | { kind: "crystal-field"; geometry?: "octahedral" | "tetrahedral" | "square-planar" }
  | { kind: "mo-diagram"; molecule?: "H2" | "N2" | "O2" | "F2" | "CO" | "NO" }
  | { kind: "kinetics-sim" };

export type QuestionChoice = {
  id: string;
  text: Bilingual;
};

export type Question = {
  id: string;
  prompt: Bilingual;
  figure?: NoteBlock;
  choices: QuestionChoice[];
  answerId: string;
  explanation: Bilingual;
  concept?: Bilingual;
  difficulty?: "easy" | "medium" | "hard";
};

