      tex: "\\underbrace{\\text{grams}}_{\\text{what you weigh}} \\;\\xrightarrow{\\;\\div M\\;}\\; \\underbrace{\\text{moles}}_{\\text{counting unit}} \\;\\xrightarrow{\\;\\times N_A\\;}\\; \\underbrace{\\text{particles}}_{\\text{atoms or molecules}}",
